mapper.select:
SELECT EVNT_ID, EVNT_SE, (SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = 'CD100' AND CD_ID = EVNT_SE) AS EVNT_SE_NM, REGEXP_REPLACE("BGNG_DT", '(.{4})(.{2})(.{2})(.{2})(.{2})(.{2})', '\1-\2-\3 \4:\5') AS BGNG_DT , REGEXP_REPLACE("END_DT", '(.{4})(.{2})(.{2})(.{2})(.{2})(.{2})', '\1-\2-\3 \4:\5') AS END_DT , EVNT_CN, EVNT_CN2, WRKR, ATCH_FILE_ID, PROCS_ID, ( SELECT PROCS_NM FROM RDIPROCSINFO_TB WHERE PROCS_ID = E.PROCS_ID ) AS PROCS_NM, FCLT_ID, ( SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = 'CD101' AND CD_ID = FCLT_ID ) AS FCLT_NM, FCLT_DTL_ID, ( SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = E.FCLT_ID AND CD_ID = E.FCLT_DTL_ID ) AS FCLT_DTL_NM
, CASE WHEN EVNT_ID = #{selected_row} THEN 'true' ELSE 'false' END AS SELECTED_ROW
FROM RDIEVNTMNG_TB E WHERE 1=1
AND (PROCS_ID = #{procs_id} OR #{procs_id} = '*')
AND FCLT_ID = #{fclt_id}
AND FCLT_DTL_ID = #{fclt_dtl_id}
AND EVNT_SE = #{evnt_se}
AND EVNT_CN LIKE '%' || #{evnt_cn} || '%'
AND EVNT_CN2 LIKE '%' || #{evnt_cn2} || '%'
AND ( (BGNG_DT <= #{bgng_dt} AND #{bgng_dt} <= END_DT) OR (BGNG_DT <= #{end_dt} AND #{end_dt} <= END_DT) OR (#{bgng_dt} <= BGNG_DT AND END_DT <= #{end_dt}) ) ORDER BY BGNG_DT, LAST_MDFCN_DT

mapper.insert:
MERGE INTO
	RDIATCHFILEMNG_TB
USING
	DUAL
ON (
	ATCH_FILE_ID = #{atch_file_id}
	AND FILE_SN = #{file_sn}
)
WHEN MATCHED THEN
	UPDATE SET
		FILE_CN = #{byte_img},
		ORGNL_FILE_NM = #{orgnl_file_nm},
		FILE_TYPE = #{file_type}
WHEN NOT MATCHED THEN
	INSERT
		(ATCH_FILE_ID,  FILE_SN, STRG_TYPE_CD , FILE_CN, ORGNL_FILE_NM, FILE_TYPE) 
	VALUES (
		#{atch_file_id}, #{file_sn}, #{strg_type_cd}, #{byte_img}, #{orgnl_file_nm}, #{file_type}
	)
